<template>
  <section class="agent-tasks">
    <header class="agent-tasks-head">
      <div>
        <span class="agent-tasks-kicker"><IconTablerBell /> {{ t('agentTasks.kicker') }}</span>
        <h3>{{ t('agentTasks.title') }}</h3>
        <p>{{ t('agentTasks.subtitle') }}</p>
      </div>
      <div class="agent-task-head-actions">
        <div class="agent-task-view-switch" role="group" :aria-label="t('agentTasks.view')">
          <button type="button" :aria-pressed="view === 'active'" @click="setView('active')">{{ t('agentTasks.activeView') }}</button>
          <button type="button" :aria-pressed="view === 'archived'" @click="setView('archived')">{{ t('agentTasks.archivedView') }}</button>
        </div>
        <select v-model="selectedTaskTemplate" :aria-label="t('agentTasks.taskTemplates')" @change="applyTaskPreset">
          <option value="">{{ t('agentTasks.taskTemplates') }}</option>
          <option value="health">{{ t('agentTasks.template.health') }}</option>
          <option value="security">{{ t('agentTasks.template.security') }}</option>
          <option value="release">{{ t('agentTasks.template.release') }}</option>
        </select>
        <button v-if="view === 'active'" type="button" @click="exportAll">{{ t('agentTasks.export') }}</button>
        <button v-if="view === 'active'" type="button" @click="importInput?.click()">{{ t('agentTasks.import') }}</button>
        <button v-if="view === 'active'" class="agent-task-create" type="button" @click="openCreate"><span aria-hidden="true">＋</span> {{ t('agentTasks.create') }}</button>
        <input ref="importInput" class="agent-task-file-input" type="file" accept="application/json,.json" @change="importFile" />
      </div>
    </header>

    <form v-if="view === 'active'" class="agent-task-command" @submit.prevent="createFromNaturalLanguage">
      <div><span>{{ t('agentTasks.naturalKicker') }}</span><strong>{{ t('agentTasks.naturalTitle') }}</strong></div>
      <input v-model="naturalInstruction" :placeholder="t('agentTasks.naturalPlaceholder')" />
      <button type="submit" :disabled="parsing || !naturalInstruction.trim()">{{ parsing ? t('agentTasks.parsing') : t('agentTasks.parse') }}</button>
    </form>

    <div v-if="error" class="agent-task-error" role="alert">{{ error }}</div>

    <div v-if="!loading && tasks.length === 0" class="agent-task-empty">
      <span class="agent-task-empty-orbit" aria-hidden="true"><IconTablerBell /></span>
      <div>
        <strong>{{ view === 'archived' ? t('agentTasks.archivedEmptyTitle') : t('agentTasks.emptyTitle') }}</strong>
        <p>{{ view === 'archived' ? t('agentTasks.archivedEmptyBody') : t('agentTasks.emptyBody') }}</p>
      </div>
      <button v-if="view === 'active'" type="button" @click="openCreate">{{ t('agentTasks.createFirst') }}</button>
    </div>

    <div v-else class="agent-task-list">
      <AgentTaskCard
        v-for="task in tasks" :key="task.id" :task="task" :latest-run="latestRun(task.id)" :runs="runsFor(task.id)"
        :busy="busyId === task.id" :expanded="expandedTaskId === task.id" :view="view"
        :project-label="projectLabel(task.cwd)" :schedule-label="scheduleLabel(task)" :permission-label="permissionLabel(task.permission)"
        @control="control(task, $event)" @edit="openEdit(task)" @remove="remove(task)" @restore="restore(task)"
        @permanently-delete="removePermanently(task)" @toggle-history="toggleTaskHistory(task.id)" @select-thread="$emit('selectThread', $event)"
      />
    </div>

    <div v-if="view === 'active'" class="system-task-divider"><span>{{ t('agentTasks.systemTasks') }}</span></div>

    <AgentTaskEditorShell v-if="editorOpen" :saving="saving"
      :kicker="editingId ? t('agentTasks.editKicker') : t('agentTasks.createKicker')"
      :title="editingId ? t('agentTasks.editTitle') : t('agentTasks.createTitle')" @close="closeEditor" @submit="save">
        <div class="agent-task-form-grid">
          <label class="wide"><span>{{ t('agentTasks.name') }}</span><input v-model="draft.name" required maxlength="120" :placeholder="t('agentTasks.namePlaceholder')" /></label>
          <label class="wide"><span>{{ t('agentTasks.description') }}</span><input v-model="draft.description" maxlength="500" :placeholder="t('agentTasks.descriptionPlaceholder')" /></label>
          <label><span>{{ t('agentTasks.workspace') }}</span>
            <select v-if="projects.length" v-model="draft.cwd" required><option value="" disabled>{{ t('agentTasks.chooseWorkspace') }}</option><option v-for="project in projects" :key="project.cwd" :value="project.cwd">{{ project.label }}</option></select>
            <input v-else v-model="draft.cwd" required placeholder="/path/to/project" />
          </label>
          <label><span>{{ t('agentTasks.promptTemplate') }}</span><select v-model="selectedPromptId" @change="applyPromptTemplate"><option value="">{{ t('agentTasks.customPrompt') }}</option><option v-for="template in visiblePrompts" :key="template.id" :value="template.id">{{ template.title }}</option></select></label>
          <label class="wide"><span>{{ t('agentTasks.prompt') }}</span><textarea v-model="draft.prompt" required rows="7" :placeholder="t('agentTasks.promptPlaceholder')" /></label>

          <label><span>{{ t('agentTasks.schedule') }}</span><select v-model="draft.scheduleKind"><option value="once">{{ t('agentTasks.scheduleOnce') }}</option><option value="interval">{{ t('agentTasks.scheduleInterval') }}</option><option value="daily">{{ t('agentTasks.scheduleDaily') }}</option><option value="weekly">{{ t('agentTasks.scheduleWeekly') }}</option><option value="monthly">{{ t('agentTasks.scheduleMonthly') }}</option><option value="cron">Cron</option></select></label>
          <label v-if="draft.scheduleKind === 'once'"><span>{{ t('agentTasks.runAt') }}</span><input v-model="draft.runAtLocal" type="datetime-local" required /></label>
          <label v-else-if="draft.scheduleKind === 'interval'"><span>{{ t('agentTasks.everyMinutes') }}</span><input v-model.number="draft.intervalMinutes" type="number" min="5" max="43200" required /></label>
          <label v-else-if="draft.scheduleKind === 'cron'"><span>Cron</span><input v-model="draft.cronExpression" required placeholder="0 9 * * 1-5" /></label>
          <template v-else>
            <fieldset v-if="draft.scheduleKind === 'weekly'" class="weekday-picker"><legend>{{ t('agentTasks.weekday') }}</legend><label v-for="day in weekdays" :key="day.value"><input v-model="draft.weekdays" type="checkbox" :value="day.value" />{{ day.label }}</label></fieldset>
            <label v-if="draft.scheduleKind === 'monthly'"><span>{{ t('agentTasks.monthDay') }}</span><input v-model.number="draft.monthDay" type="number" min="1" max="31" required /></label>
            <label><span>{{ t('agentTasks.time') }}</span><input v-model="draft.time" type="time" required /></label>
          </template>
          <label><span>{{ t('agentTasks.timezone') }}</span><input v-model="draft.timezone" required /></label>
          <label v-if="draft.scheduleKind === 'daily'" class="check-label"><input v-model="draft.weekdaysOnly" type="checkbox" /><span>{{ t('agentTasks.weekdaysOnly') }}</span></label>
          <label v-if="['daily','weekly','monthly'].includes(draft.scheduleKind)" class="wide"><span>{{ t('agentTasks.excludedDates') }}</span><input v-model="draft.excludedDates" placeholder="2026-10-01, 2026-10-02" /></label>

          <label><span>{{ t('agentTasks.permission') }}</span><select v-model="draft.permission"><option value="read-only">{{ t('agentTasks.readOnly') }}</option><option value="workspace-write">{{ t('agentTasks.workspaceWrite') }}</option></select></label>
          <label><span>{{ t('agentTasks.model') }}</span><input v-model="draft.model" :placeholder="t('agentTasks.workspaceDefault')" /></label>
          <label><span>{{ t('agentTasks.effort') }}</span><select v-model="draft.effort"><option value="">{{ t('agentTasks.workspaceDefault') }}</option><option v-for="effort in efforts" :key="effort" :value="effort">{{ effort }}</option></select></label>
          <label><span>{{ t('agentTasks.timeout') }}</span><input v-model.number="draft.timeoutMinutes" type="number" min="5" max="240" required /></label>
          <label><span>{{ t('agentTasks.retries') }}</span><input v-model.number="draft.maxRetries" type="number" min="0" max="5" required /></label>
          <label><span>{{ t('agentTasks.concurrency') }}</span><select v-model="draft.concurrencyPolicy"><option value="skip">{{ t('agentTasks.concurrency.skip') }}</option><option value="queue">{{ t('agentTasks.concurrency.queue') }}</option><option value="replace">{{ t('agentTasks.concurrency.replace') }}</option></select></label>
          <label><span>{{ t('agentTasks.notifications') }}</span><select v-model="draft.notificationPolicy"><option value="off">{{ t('agentTasks.notifications.off') }}</option><option value="important">{{ t('agentTasks.notifications.important') }}</option><option value="all">{{ t('agentTasks.notifications.all') }}</option></select></label>
          <fieldset class="agent-task-conversation-mode wide">
            <legend>{{ t('agentTasks.conversationMode') }}</legend>
            <label :class="{ selected: draft.conversationMode === 'new' }">
              <input v-model="draft.conversationMode" type="radio" value="new" />
              <span><strong>{{ t('agentTasks.conversationMode.new') }}</strong><small>{{ t('agentTasks.conversationMode.newHint') }}</small></span>
            </label>
            <label :class="{ selected: draft.conversationMode === 'reuse' }">
              <input v-model="draft.conversationMode" type="radio" value="reuse" />
              <span><strong>{{ t('agentTasks.conversationMode.reuse') }}</strong><small>{{ t('agentTasks.conversationMode.reuseHint') }}</small></span>
            </label>
          </fieldset>
          <label><span>{{ t('agentTasks.maxTokens') }}</span><input v-model.number="draft.maxTokens" type="number" min="0" max="10000000" step="1000" /></label>
          <label><span>{{ t('agentTasks.pauseAfterFailures') }}</span><input v-model.number="draft.pauseAfterFailures" type="number" min="1" max="20" /></label>
          <label><span>{{ t('agentTasks.output') }}</span><select v-model="draft.outputMode"><option value="conversation">{{ t('agentTasks.output.conversation') }}</option><option value="file">{{ t('agentTasks.output.file') }}</option><option value="notification">{{ t('agentTasks.output.notification') }}</option><option value="file-and-notification">{{ t('agentTasks.output.both') }}</option></select></label>
          <label v-if="draft.outputMode === 'file' || draft.outputMode === 'file-and-notification'"><span>{{ t('agentTasks.outputPath') }}</span><input v-model="draft.outputPath" required placeholder="reports/agent-tasks.md" /></label>
        </div>
        <section v-if="editingId" class="agent-task-versions">
          <div><strong>{{ t('agentTasks.versions') }}</strong><small>{{ t('agentTasks.versionsHint') }}</small></div>
          <button v-for="version in versions" :key="version.version" type="button" :disabled="version.version === currentVersion" @click="rollback(version.version)">v{{ version.version }} · {{ formatTime(version.createdAtIso) }}</button>
        </section>
        <aside class="agent-task-safety"><IconTablerSettings /><div><strong>{{ t('agentTasks.safetyTitle') }}</strong><p>{{ draft.permission === 'workspace-write' ? t('agentTasks.safetyWrite') : t('agentTasks.safetyRead') }}</p></div></aside>
        <p v-if="editorHint" class="agent-task-hint">{{ editorHint }}</p>
        <p v-if="editorError" class="agent-task-error" role="alert">{{ editorError }}</p>
    </AgentTaskEditorShell>
  </section>
</template>

<script setup lang="ts">
import { computed, onMounted, onUnmounted, reactive, ref } from 'vue'
import { controlAgentTask, createAgentTask, deleteAgentTask, exportAgentTasks, fetchAgentTaskRuns, fetchAgentTasks, fetchAgentTaskVersions, importAgentTasks, parseAgentTask, rollbackAgentTask, updateAgentTask, type AgentTask, type AgentTaskInput, type AgentTaskRun, type AgentTaskVersion } from '../../api/codexAgentTaskClient'
import { fetchPromptTemplates } from '../../api/codexPromptLibraryClient'
import type { PromptTemplate } from '../../composables/promptLibraryRules'
import { useLocale } from '../../composables/useLocale'
import IconTablerBell from '../icons/IconTablerBell.vue'
import IconTablerSettings from '../icons/IconTablerSettings.vue'
import AgentTaskCard from './AgentTaskCard.vue'
import AgentTaskEditorShell from './AgentTaskEditorShell.vue'

type ProjectOption = { cwd: string; label: string }
const props = withDefaults(defineProps<{ projects?: ProjectOption[] }>(), { projects: () => [] })
defineEmits<{ selectThread: [threadId: string] }>()
const { locale, t } = useLocale()
const tasks = ref<AgentTask[]>([])
const view = ref<'active' | 'archived'>('active')
const runs = ref<AgentTaskRun[]>([])
const prompts = ref<PromptTemplate[]>([])
const loading = ref(false)
const saving = ref(false)
const busyId = ref('')
const error = ref('')
const editorError = ref('')
const editorHint = ref('')
const editorOpen = ref(false)
const editingId = ref('')
const expandedTaskId = ref('')
const taskRuns = ref<Record<string, AgentTaskRun[]>>({})
const versions = ref<AgentTaskVersion[]>([])
const currentVersion = ref(0)
const selectedPromptId = ref('')
const selectedTaskTemplate = ref('')
const naturalInstruction = ref('')
const parsing = ref(false)
const importInput = ref<HTMLInputElement | null>(null)
let refreshTimer: number | null = null
let loadRevision = 0

const defaultTimezone = Intl.DateTimeFormat().resolvedOptions().timeZone || 'UTC'
const efforts = ['minimal', 'low', 'medium', 'high', 'xhigh'] as const
const draft = reactive({ name: '', description: '', cwd: '', prompt: '', scheduleKind: 'daily' as AgentTaskInput['schedule']['kind'], runAtLocal: '', intervalMinutes: 60, weekday: 1, weekdays: [1] as number[], monthDay: 1, time: '09:00', cronExpression: '0 9 * * 1-5', weekdaysOnly: false, excludedDates: '', timezone: defaultTimezone, model: '', effort: '', permission: 'read-only' as AgentTaskInput['permission'], enabled: true, timeoutMinutes: 45, maxRetries: 1, concurrencyPolicy: 'skip' as AgentTaskInput['concurrencyPolicy'], notificationPolicy: 'important' as AgentTaskInput['notificationPolicy'], conversationMode: 'new' as AgentTaskInput['conversationMode'], outputMode: 'conversation' as AgentTaskInput['outputMode'], outputPath: 'reports/agent-tasks.md', maxTokens: 0, pauseAfterFailures: 3 })
const weekdays = computed(() => [0,1,2,3,4,5,6].map((value) => ({ value, label: new Intl.DateTimeFormat(locale.value, { weekday: 'long', timeZone: 'UTC' }).format(new Date(Date.UTC(2026, 6, 12 + value))) })))
const visiblePrompts = computed(() => prompts.value.filter((template) => template.scope === 'global' || !draft.cwd || template.workspaceCwd === draft.cwd))

function localDateTime(date: Date): string { const offset = date.getTimezoneOffset() * 60_000; return new Date(date.getTime() - offset).toISOString().slice(0, 16) }
function resetDraft(): void { Object.assign(draft, { name: '', description: '', cwd: props.projects[0]?.cwd ?? '', prompt: '', scheduleKind: 'daily', runAtLocal: localDateTime(new Date(Date.now() + 60 * 60_000)), intervalMinutes: 60, weekday: 1, weekdays: [1], monthDay: 1, time: '09:00', cronExpression: '0 9 * * 1-5', weekdaysOnly: false, excludedDates: '', timezone: defaultTimezone, model: '', effort: '', permission: 'read-only', enabled: true, timeoutMinutes: 45, maxRetries: 1, concurrencyPolicy: 'skip', notificationPolicy: 'important', conversationMode: 'new', outputMode: 'conversation', outputPath: 'reports/agent-tasks.md', maxTokens: 0, pauseAfterFailures: 3 }); selectedPromptId.value = ''; editorError.value = ''; editorHint.value = ''; versions.value = []; currentVersion.value = 0 }
function openCreate(): void { editingId.value = ''; resetDraft(); editorOpen.value = true }
function openEdit(task: AgentTask): void { editingId.value = task.id; resetDraft(); const timed = task.schedule.kind === 'daily' || task.schedule.kind === 'weekly' || task.schedule.kind === 'monthly' ? task.schedule : null; Object.assign(draft, { name: task.name, description: task.description, cwd: task.cwd, prompt: task.prompt, scheduleKind: task.schedule.kind, runAtLocal: task.schedule.kind === 'once' ? localDateTime(new Date(task.schedule.runAtIso)) : draft.runAtLocal, intervalMinutes: task.schedule.kind === 'interval' ? task.schedule.intervalMinutes : 60, weekday: task.schedule.kind === 'weekly' ? task.schedule.weekday : 1, weekdays: task.schedule.kind === 'weekly' ? [...(task.schedule.weekdays ?? [task.schedule.weekday])] : [1], monthDay: task.schedule.kind === 'monthly' ? task.schedule.day : 1, time: timed?.time ?? '09:00', cronExpression: task.schedule.kind === 'cron' ? task.schedule.expression : '0 9 * * 1-5', weekdaysOnly: task.schedule.kind === 'daily' && task.schedule.weekdaysOnly === true, excludedDates: timed?.excludedDates?.join(', ') ?? '', timezone: task.timezone, model: task.model, effort: task.effort ?? '', permission: task.permission, enabled: task.enabled, timeoutMinutes: task.timeoutMinutes, maxRetries: task.maxRetries, concurrencyPolicy: task.concurrencyPolicy, notificationPolicy: task.notificationPolicy, conversationMode: task.conversationMode, outputMode: task.outputMode, outputPath: task.outputPath || 'reports/agent-tasks.md', maxTokens: task.maxTokens, pauseAfterFailures: task.pauseAfterFailures }); currentVersion.value = task.version; editorOpen.value = true; void fetchAgentTaskVersions(task.id).then((value) => { versions.value = value }).catch(() => undefined) }
function closeEditor(): void { if (!saving.value) editorOpen.value = false }
function applyPromptTemplate(): void { const template = prompts.value.find((value) => value.id === selectedPromptId.value); if (template) { draft.prompt = template.content; if (!draft.name) draft.name = template.title } }
function applyTaskPreset(): void { const value = selectedTaskTemplate.value; if (!value) return; openCreate(); if (value === 'health') Object.assign(draft, { name: t('agentTasks.template.health'), description: t('agentTasks.template.healthBody'), prompt: t('agentTasks.template.healthPrompt'), scheduleKind: 'daily', weekdaysOnly: true, time: '09:00' }); else if (value === 'security') Object.assign(draft, { name: t('agentTasks.template.security'), description: t('agentTasks.template.securityBody'), prompt: t('agentTasks.template.securityPrompt'), scheduleKind: 'weekly', weekday: 1, time: '10:00', effort: 'high' }); else Object.assign(draft, { name: t('agentTasks.template.release'), description: t('agentTasks.template.releaseBody'), prompt: t('agentTasks.template.releasePrompt'), scheduleKind: 'weekly', weekday: 5, time: '16:00', outputMode: 'file', outputPath: 'reports/weekly-release.md' }); selectedTaskTemplate.value = '' }
function input(): AgentTaskInput { const excludedDates = draft.excludedDates.split(',').map((value) => value.trim()).filter(Boolean); const selectedWeekdays = [...new Set(draft.weekdays)].sort(); if (draft.scheduleKind === 'weekly' && selectedWeekdays.length === 0) throw new Error(t('agentTasks.weekdayRequired')); const schedule: AgentTaskInput['schedule'] = draft.scheduleKind === 'once' ? { kind: 'once', runAtIso: new Date(draft.runAtLocal).toISOString() } : draft.scheduleKind === 'interval' ? { kind: 'interval', intervalMinutes: draft.intervalMinutes } : draft.scheduleKind === 'weekly' ? { kind: 'weekly', weekday: selectedWeekdays[0]!, weekdays: selectedWeekdays, time: draft.time, excludedDates } : draft.scheduleKind === 'monthly' ? { kind: 'monthly', day: draft.monthDay, time: draft.time, excludedDates } : draft.scheduleKind === 'cron' ? { kind: 'cron', expression: draft.cronExpression } : { kind: 'daily', time: draft.time, weekdaysOnly: draft.weekdaysOnly, excludedDates }; return { name: draft.name, description: draft.description, cwd: draft.cwd, prompt: draft.prompt, schedule, timezone: draft.timezone, model: draft.model, effort: draft.effort ? draft.effort as AgentTaskInput['effort'] : null, permission: draft.permission, enabled: draft.enabled, timeoutMinutes: draft.timeoutMinutes, maxRetries: draft.maxRetries, concurrencyPolicy: draft.concurrencyPolicy, notificationPolicy: draft.notificationPolicy, conversationMode: draft.conversationMode, outputMode: draft.outputMode, outputPath: draft.outputPath, maxTokens: draft.maxTokens, pauseAfterFailures: draft.pauseAfterFailures } }

async function load(silent = false): Promise<void> { const revision = ++loadRevision; if (!silent) loading.value = true; try { const result = await fetchAgentTasks(view.value); if (revision !== loadRevision) return; tasks.value = result.tasks; runs.value = result.runs; error.value = '' } catch (value) { if (revision === loadRevision) error.value = value instanceof Error ? value.message : t('agentTasks.loadFailed') } finally { if (revision === loadRevision) loading.value = false } }
async function save(): Promise<void> { saving.value = true; editorError.value = ''; try { if (editingId.value) await updateAgentTask(editingId.value, input()); else await createAgentTask(input()); editorOpen.value = false; await load(true) } catch (value) { editorError.value = value instanceof Error ? value.message : t('agentTasks.saveFailed') } finally { saving.value = false } }
async function control(task: AgentTask, action: 'run' | 'pause' | 'resume' | 'cancel' | 'duplicate'): Promise<void> { busyId.value = task.id; try { await controlAgentTask(task.id, action, activeRun(task.id)?.id ?? latestRun(task.id)?.id); await load(true) } catch (value) { error.value = value instanceof Error ? value.message : t('agentTasks.controlFailed') } finally { busyId.value = '' } }
async function toggleTaskHistory(taskId: string): Promise<void> { if (expandedTaskId.value === taskId) { expandedTaskId.value = ''; return } expandedTaskId.value = taskId; const history = await fetchAgentTaskRuns(taskId, 50).catch(() => []); if (expandedTaskId.value === taskId && history.length > 0) taskRuns.value = { ...taskRuns.value, [taskId]: history } }
async function rollback(version: number): Promise<void> { if (!editingId.value || !window.confirm(t('agentTasks.rollbackConfirm', { version: String(version) }))) return; saving.value = true; try { const task = await rollbackAgentTask(editingId.value, version); openEdit(task); await load(true) } catch (value) { editorError.value = value instanceof Error ? value.message : t('agentTasks.saveFailed') } finally { saving.value = false } }
async function createFromNaturalLanguage(): Promise<void> { parsing.value = true; error.value = ''; try { const result = await parseAgentTask(naturalInstruction.value, defaultTimezone); openCreate(); draft.name = result.name; draft.prompt = result.prompt; draft.timezone = result.timezone; applySchedule(result.schedule); editorHint.value = `${t('agentTasks.ruleDraftReview')} ${result.explanation}` } catch (value) { error.value = value instanceof Error ? value.message : t('agentTasks.parseFailed') } finally { parsing.value = false } }
function applySchedule(schedule: AgentTaskInput['schedule']): void { draft.scheduleKind = schedule.kind; if (schedule.kind === 'once') draft.runAtLocal = localDateTime(new Date(schedule.runAtIso)); else if (schedule.kind === 'interval') draft.intervalMinutes = schedule.intervalMinutes; else if (schedule.kind === 'cron') draft.cronExpression = schedule.expression; else { draft.time = schedule.time; draft.excludedDates = schedule.excludedDates?.join(', ') ?? ''; if (schedule.kind === 'weekly') { draft.weekday = schedule.weekday; draft.weekdays = [...(schedule.weekdays ?? [schedule.weekday])] } if (schedule.kind === 'monthly') draft.monthDay = schedule.day; if (schedule.kind === 'daily') draft.weekdaysOnly = schedule.weekdaysOnly === true } }
async function exportAll(): Promise<void> { try { const payload = await exportAgentTasks(); const url = URL.createObjectURL(new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' })); const link = document.createElement('a'); link.href = url; link.download = `cody-agent-tasks-${new Date().toISOString().slice(0,10)}.json`; link.click(); URL.revokeObjectURL(url) } catch (value) { error.value = value instanceof Error ? value.message : t('agentTasks.exportFailed') } }
async function importFile(event: Event): Promise<void> { const input = event.target as HTMLInputElement; const file = input.files?.[0]; if (!file) return; try { await importAgentTasks(JSON.parse(await file.text())); await load(true) } catch (value) { error.value = value instanceof Error ? value.message : t('agentTasks.importFailed') } finally { input.value = '' } }
async function remove(task: AgentTask): Promise<void> { if (!window.confirm(t('agentTasks.deleteConfirm', { name: task.name }))) return; busyId.value = task.id; try { await deleteAgentTask(task.id); await load(true) } catch (value) { error.value = value instanceof Error ? value.message : t('agentTasks.deleteFailed') } finally { busyId.value = '' } }
async function restore(task: AgentTask): Promise<void> { busyId.value = task.id; try { await controlAgentTask(task.id, 'restore'); await load(true) } catch (value) { error.value = value instanceof Error ? value.message : t('agentTasks.restoreFailed') } finally { busyId.value = '' } }
async function removePermanently(task: AgentTask): Promise<void> { if (!window.confirm(t('agentTasks.permanentDeleteConfirm', { name: task.name }))) return; busyId.value = task.id; try { await deleteAgentTask(task.id, true); await load(true) } catch (value) { error.value = value instanceof Error ? value.message : t('agentTasks.deleteFailed') } finally { busyId.value = '' } }
function setView(next: 'active' | 'archived'): void { if (view.value === next) return; view.value = next; expandedTaskId.value = ''; taskRuns.value = {}; void load() }
function activeRun(taskId: string): AgentTaskRun | undefined { return runs.value.find((run) => run.taskId === taskId && ['running','waiting_approval'].includes(run.status)) }
function latestRun(taskId: string): AgentTaskRun | undefined { return activeRun(taskId) ?? runs.value.find((run) => run.taskId === taskId) }
function runsFor(taskId: string): AgentTaskRun[] { return (taskRuns.value[taskId] ?? runs.value.filter((run) => run.taskId === taskId)).slice(0, 50) }
function projectLabel(cwd: string): string { return props.projects.find((project) => project.cwd === cwd)?.label ?? cwd.split('/').filter(Boolean).at(-1) ?? cwd }
function permissionLabel(value: AgentTask['permission']): string { return value === 'workspace-write' ? t('agentTasks.workspaceWrite') : t('agentTasks.readOnly') }
function formatTime(value: string | null): string { if (!value) return t('agentTasks.notScheduled'); const date = new Date(value); return Number.isFinite(date.getTime()) ? new Intl.DateTimeFormat(locale.value, { dateStyle: 'medium', timeStyle: 'short' }).format(date) : value }
function scheduleLabel(task: AgentTask): string { const value = task.schedule; if (value.kind === 'once') return t('agentTasks.onceAt', { time: formatTime(value.runAtIso) }); if (value.kind === 'interval') return t('agentTasks.everyNMinutes', { count: String(value.intervalMinutes) }); if (value.kind === 'cron') return `Cron ${value.expression}`; if (value.kind === 'monthly') return t('agentTasks.monthlyAt', { day: String(value.day), time: value.time }); if (value.kind === 'daily') return value.weekdaysOnly ? t('agentTasks.weekdaysAt', { time: value.time }) : t('agentTasks.dailyAt', { time: value.time }); const labels = (value.weekdays ?? [value.weekday]).map((weekday) => weekdays.value.find((day) => day.value === weekday)?.label ?? String(weekday)).join('、'); return t('agentTasks.weeklyAt', { day: labels, time: value.time }) }

onMounted(() => { void Promise.all([load(), fetchPromptTemplates().then((value) => { prompts.value = value }).catch(() => undefined)]); refreshTimer = window.setInterval(() => void load(true), 5_000) })
onUnmounted(() => { if (refreshTimer !== null) window.clearInterval(refreshTimer) })
</script>

